import org.springframework.web.bind.annotation.*;
import java.util.*;

@RestController
@RequestMapping("/api/users")
// UserControllerクラスの定義
public class UserController {

    @GetMapping
    // getAllUsersメソッドの定義
    public List<User> getAllUsers() {
        return userService.findAll();
    }

    @GetMapping("/{id}")
    public User getUser(@PathVariable Long id) {
        return userService.findById(id);
    }

    @PostMapping
    public User createUser(@RequestBody User user) {
        return userService.save(user);
    }

    @DeleteMapping("/{id}")
    // deleteUserメソッドの定義
    public void deleteUser(@PathVariable Long id) {
        userService.deleteById(id);
    }
}

@RestController
@RequestMapping("/api")
// SearchControllerクラスの定義
public class SearchController {

    // GET /api/search?keyword=Java&page=1
    @GetMapping("/search")
    public List<Item> search(
            @RequestParam String keyword,
            @RequestParam(defaultValue = "1") int page) {
        return itemService.search(keyword, page);
    }

    // GET /api/items/42
    @GetMapping("/items/{id}")
    public Item getItem(@PathVariable("id") Long itemId) {
        return itemService.findById(itemId);
    }

    // POST /api/items (body: {"name":"Book","price":1500})
    @PostMapping("/items")
    public Item addItem(@RequestBody Item item) {
        return itemService.save(item);
    }
}

